import './App.css';
import ReactJson from 'react-json-view'

import {
  BrowserView,
  MobileView,
  IOSView,
  AndroidView
} from "react-device-detect";

const queryString = require('query-string');
const payloadString = parsePayload();
const payloadJSON = JSON.parse(payloadString);

function App() {
  return (
    <div>
      <div className="App">
        <h3>Alexa Connected Devices</h3>
        <div className="logo">
          <img src="https://d3ogm7ac91k97u.cloudfront.net/content/dam/alexa/blog/blog_quick-links_954x240.png"
            width="600" alt="logo"></img>
        </div>
      </div>
      <h4>Payload</h4>
      {payloadJSON && <ReactJson src={payloadJSON} theme="monokai" />}
      <h4>UserAgent</h4>
      <BrowserView>
        <h5> This is Web application to perform device provisioning </h5>
      </BrowserView>
      <MobileView>
        <h5> Click here to open Commissioning Mobile app </h5>
      </MobileView>
      <AndroidView>
        <h5> Open  ANDROID App </h5>
        <a href="alexa://?fragment=12345">Click here</a>
      </AndroidView>
      <IOSView>
        <h5> Click here to open  IOS App </h5>
        <a href="alexa://?fragment=12345">Click here</a>
      </IOSView>
    </div>
  );
}

function parsePayload() {
  if (window.location.search) {
    const base64payload = queryString.parse(window.location.search);
    if (base64payload) {
      const payloadString = atob(base64payload?.data);
      console.log(JSON.parse(payloadString));
      return payloadString;
    }
  }

  return null;
}

export default App;
